"use client";
import { useState } from "react";
import {
  MinusCircle,
  Tag,
  MapPin,
  Calendar,
  ScrollText,
  CheckCircle,
  Upload,
} from "lucide-react";

const InputField = ({
  icon: Icon,
  label,
  name,
  type = "text",
  required = true,
  placeholder,
  children,
  className = "",
  value,
  onChange,
  disabled,
}) => (
  <div className={`space-y-1 ${className}`}>
    <label htmlFor={name} className="block text-sm font-medium text-gray-700">
      {label} {required && <span className="text-red-500">*</span>}
    </label>
    <div className="relative">
      <Icon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
      {children || (
        <input
          id={name}
          name={name}
          type={type}
          placeholder={placeholder}
          value={value}
          onChange={onChange}
          required={required}
          disabled={disabled}
          className="w-full h-12 border border-gray-300 rounded-xl p-3 pl-10 focus:outline-none focus:ring-2 focus:ring-red-400 transition duration-200 shadow-sm"
        />
      )}
    </div>
  </div>
);

export default function ReportLostItemForm() {
  const initialFormState = {
    name: "",
    category: "",
    location: "",
    description: "",
    date: new Date().toISOString().split("T")[0],
    imageFile: null,
  };

  const [formData, setFormData] = useState(initialFormState);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState(null);

  const categories = [
    "Electronics",
    "Wallet",
    "Keys",
    "Textbook",
    "Clothing",
    "Jewelry",
    "Bags/Backpacks",
    "Documents",
    "Other",
  ];

  const handleChange = (e) => {
    const { name, value, files } = e.target;

    if (name === "imageFile" && files && files.length > 0) {
      setFormData((prev) => ({ ...prev, imageFile: files[0] }));
    } else {
      setFormData((prev) => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage(null);
    setIsSubmitting(true);

    if (
      !formData.name ||
      !formData.category ||
      !formData.location ||
      !formData.description
    ) {
      setMessage({
        type: "error",
        text: "Please fill out all required fields.",
      });
      setIsSubmitting(false);
      return;
    }

    try {
      const token = localStorage.getItem("accessToken");
      if (!token) {
        setMessage({ type: "error", text: "Please login first." });
        setIsSubmitting(false);
        return;
      }

      const formDataToSend = new FormData();
      formDataToSend.append("itemName", formData.name);
      formDataToSend.append("category", formData.category);
      formDataToSend.append("location", formData.location);
      formDataToSend.append("description", formData.description);
      formDataToSend.append("date", formData.date);
      formDataToSend.append("status", "Lost");

      if (formData.imageFile) {
        formDataToSend.append("photos", formData.imageFile);
      }

      const res = await fetch("http://localhost:5000/report/lostItem", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
        },
        body: formDataToSend,
      });

      const data = await res.json();

      if (!res.ok) throw new Error(data.message || "Submission failed");

      setMessage({
        type: "success",
        text: "Lost item report submitted successfully!",
      });

      setFormData(initialFormState);
    } catch (err) {
      console.error(err);
      setMessage({
        type: "error",
        text: "Submission failed. Please try again.",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-gray-50 p-4 sm:p-8 flex justify-center items-start">
      <div className="w-full max-w-3xl bg-white rounded-2xl shadow-2xl p-6 sm:p-10 my-4 border-t-4 border-red-600">
        <div className="flex items-center space-x-3 mb-8 pb-4 border-b">
          <MinusCircle className="w-8 h-8 text-red-600" />
          <h1 className="text-3xl font-bold text-red-700">
            Report a Lost Item
          </h1>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <InputField
              icon={Tag}
              label="Item Name"
              name="name"
              placeholder="e.g., Black Leather Wallet"
              value={formData.name}
              onChange={handleChange}
              disabled={isSubmitting}
            />

            <InputField icon={Tag} label="Category" name="category">
              <select
                id="category"
                name="category"
                value={formData.category}
                onChange={handleChange}
                required
                disabled={isSubmitting}
                className="w-full h-12 border border-gray-300 bg-white rounded-xl p-3 pl-10 focus:outline-none focus:ring-2 focus:ring-red-400 transition duration-200 shadow-sm"
              >
                <option value="" disabled>
                  Select a category
                </option>
                {categories.map((cat) => (
                  <option key={cat} value={cat}>
                    {cat}
                  </option>
                ))}
              </select>
            </InputField>

            <InputField
              icon={MapPin}
              label="Last Known Location"
              name="location"
              placeholder="e.g., Library 3rd Floor"
              value={formData.location}
              onChange={handleChange}
              disabled={isSubmitting}
            />

            <InputField
              icon={Calendar}
              label="Date Lost"
              name="date"
              type="date"
              required={false}
              value={formData.date}
              onChange={handleChange}
              disabled={isSubmitting}
            />
          </div>

          <div className="col-span-full">
            <label className="block text-sm font-medium text-gray-700">
              Description (Required) <span className="text-red-500">*</span>
            </label>
            <div className="relative mt-1">
              <ScrollText className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
              <textarea
                name="description"
                value={formData.description}
                onChange={handleChange}
                required
                rows={4}
                disabled={isSubmitting}
                className="w-full border border-gray-300 rounded-xl p-3 pl-10 focus:outline-none focus:ring-2 focus:ring-red-400 transition duration-200 shadow-sm"
              />
            </div>
          </div>

          <div className="space-y-1 col-span-full">
            <label className="block text-sm font-medium text-gray-700">
              Upload Item Photo (Optional)
            </label>
            <div className="relative border-2 border-dashed border-gray-300 p-4 rounded-xl flex flex-col items-center justify-center bg-gray-50">
              <Upload className="w-6 h-6 text-gray-500 mb-2" />
              <p className="text-sm text-gray-600">
                {formData.imageFile
                  ? `File Selected: ${formData.imageFile.name}`
                  : "Drag and drop or click to select a file"}
              </p>
              <input
                name="imageFile"
                type="file"
                accept="image/*"
                onChange={handleChange}
                disabled={isSubmitting}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              />
            </div>
          </div>

          {message && (
            <div
              className={`p-4 rounded-xl flex items-center space-x-3 ${
                message.type === "error"
                  ? "bg-red-100 text-red-700"
                  : "bg-green-100 text-green-700"
              }`}
            >
              <CheckCircle className="w-5 h-5" />
              <p className="font-medium text-sm">{message.text}</p>
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className={`w-full py-3 mt-4 text-white font-semibold rounded-xl transition duration-300 flex items-center justify-center space-x-3 shadow-lg 
              ${
                isSubmitting
                  ? "bg-red-400 cursor-not-allowed"
                  : "bg-red-600 hover:bg-red-700"
              }`}
          >
            {isSubmitting ? "Submitting..." : "Submit Lost Item Report"}
          </button>
        </form>
      </div>
    </div>
  );
}
